function Movie({coverImg, title, summary, genres}) {
  return (
    <div key={id}>
      <h2>{title}</h2>
      <img src={coverImg}></img>
      <p>{summary}</p>
      <ul>
        {genres?.map((g) => (
          <li key={g}>{g}</li>
        ))}
      </ul>
    </div>
  )
}
